219:     /**
220:      * Authorize an action based on the current set of ACLs.
221:      *
222:      * In order to know whether to allow or deny the action, we need to examine the ACLs
223:      * that apply to it. If any DENY ACLs match, the operation is denied, no matter how
224:      * many ALLOW ACLs match. If neither ALLOW nor DENY ACLs match, we return the default
225:      * result. In general it makes more sense to configure the default result to be
226:      * DENY, but some people (and unit tests) configure it as ALLOW.
227:      */
228:     public AuthorizationResult authorize(
229:         AuthorizableRequestContext requestContext,
230:         Action action
231:     ) {
232:         if (action.resourcePattern().patternType() != LITERAL) {
233:             throw new IllegalArgumentException("Only literal resources are supported. Got: " + action.resourcePattern().patternType());
234:         }
235:         KafkaPrincipal principal = baseKafkaPrincipal(requestContext);
236:         final MatchingRule rule;
237: 
238:         // Superusers are authorized to do anything.
239:         if (superUsers.contains(principal.toString())) {
240:             rule = SuperUserRule.INSTANCE;
241:         } else if (!loadingComplete) {
242:             throw new AuthorizerNotReadyException();
243:         } else {
244:             rule = findAclRule(
245:                 matchingPrincipals(requestContext),
246:                 requestContext.clientAddress().getHostAddress(),
247:                 action
248:             );
249:         }
250:         logAuditMessage(principal, requestContext, action, rule);
251:         return rule.result();
252:     }
253: 
254:     private String buildAuditMessage(
255:         KafkaPrincipal principal,
256:         AuthorizableRequestContext context,
257:         Action action,
258:         MatchingRule rule
259:     ) {
260:         StringBuilder bldr = new StringBuilder();
261:         bldr.append("Principal = ").append(principal);
262:         bldr.append(" is ").append(rule.result() == ALLOWED ? "Allowed" : "Denied");
263:         bldr.append(" operation = ").append(action.operation());
264:         bldr.append(" from host = ").append(context.clientAddress().getHostAddress());
265:         bldr.append(" on resource = ");
266:         appendResourcePattern(action.resourcePattern(), bldr);
267:         bldr.append(" for request = ").append(ApiKeys.forId(context.requestType()).name);
268:         bldr.append(" with resourceRefCount = ").append(action.resourceReferenceCount());
269:         bldr.append(" based on rule ").append(rule);
270:         return bldr.toString();
271:     }
272: 
273:     private void appendResourcePattern(ResourcePattern resourcePattern, StringBuilder bldr) {
274:         bldr.append(SecurityUtils.resourceTypeName(resourcePattern.resourceType()))
275:             .append(":")
276:             .append(resourcePattern.patternType())
277:             .append(":")
278:             .append(resourcePattern.name());
279:     }
