281:     private void logAuditMessage(
282:         KafkaPrincipal principal,
283:         AuthorizableRequestContext requestContext,
284:         Action action,
285:         MatchingRule rule
286:     ) {
287:         switch (rule.result()) {
288:             case ALLOWED:
289:                 // logIfAllowed is true if access is granted to the resource as a result of this authorization.
290:                 // In this case, log at debug level. If false, no access is actually granted, the result is used
291:                 // only to determine authorized operations. So log only at trace level.
292:                 if (action.logIfAllowed() && auditLog.isDebugEnabled()) {
293:                     auditLog.debug(buildAuditMessage(principal, requestContext, action, rule));
294:                 } else if (auditLog.isTraceEnabled()) {
295:                     auditLog.trace(buildAuditMessage(principal, requestContext, action, rule));
296:                 }
297:                 return;
298: 
299:             case DENIED:
300:                 // logIfDenied is true if access to the resource was explicitly requested. Since this is an attempt
301:                 // to access unauthorized resources, log at info level. If false, this is either a request to determine
302:                 // authorized operations or a filter (e.g for regex subscriptions) to filter out authorized resources.
303:                 // In this case, log only at trace level.
304:                 if (action.logIfDenied()) {
305:                     auditLog.info(buildAuditMessage(principal, requestContext, action, rule));
306:                 } else if (auditLog.isTraceEnabled()) {
307:                     auditLog.trace(buildAuditMessage(principal, requestContext, action, rule));
308:                 }
309:         }
310:     }
