312:     private MatchingRule findAclRule(
313:         Set<KafkaPrincipal> matchingPrincipals,
314:         String host,
315:         Action action
316:     ) {
317:         // This code relies on the ordering of StandardAcl within the NavigableMap.
318:         // Entries are sorted by resource type first, then REVERSE resource name.
319:         // Therefore, we can find all the applicable ACLs by starting at
320:         // (resource_type, resource_name) and stepping forwards until we reach
321:         // an ACL with a resource name which is not a prefix of the current one.
322:         // At that point, we need to search for if there are any more ACLs at
323:         // the first divergence point.
324:         //
325:         // For example, when trying to authorize a TOPIC resource named foobar, we would
326:         // start at element 2, and continue on to 3 and 4 following map:
327:         //
328:         // 1. rs=TOPIC rn=gar pt=PREFIX
329:         // 2. rs=TOPIC rn=foobar pt=PREFIX
330:         // 3. rs=TOPIC rn=foob pt=LITERAL
331:         // 4. rs=TOPIC rn=foo pt=PREFIX
332:         // 5. rs=TOPIC rn=fb pt=PREFIX
333:         // 6. rs=TOPIC rn=fa pt=PREFIX
334:         // 7. rs=TOPIC rn=f  pt=PREFIX
335:         // 8. rs=TOPIC rn=eeee pt=LITERAL
336:         //
337:         // Once we reached element 5, we would jump to element 7.
338:         MatchingRuleBuilder matchingRuleBuilder = new MatchingRuleBuilder(noAclRule);
339:         StandardAcl exemplar = new StandardAcl(
340:             action.resourcePattern().resourceType(),
341:             action.resourcePattern().name(),
342:             PatternType.UNKNOWN, // Note that the UNKNOWN value sorts before all others.
343:             "",
344:             "",
345:             AclOperation.UNKNOWN,
346:             AclPermissionType.UNKNOWN);
347:         AclCache aclCacheSnapshot = aclCache;
348:         checkSection(aclCacheSnapshot, action, exemplar, matchingPrincipals, host, matchingRuleBuilder);
349:         if (matchingRuleBuilder.foundDeny()) {
350:             return matchingRuleBuilder.build();
351:         }
352: 
353:         // In addition to ACLs for this specific resource name, there can also be wildcard
354:         // ACLs that match any resource name. These are stored as type = LITERAL,
355:         // name = "*". We search these next.
356:         exemplar = new StandardAcl(
357:             action.resourcePattern().resourceType(),
358:             WILDCARD,
359:             LITERAL,
360:             "",
361:             "",
362:             AclOperation.UNKNOWN,
363:             AclPermissionType.UNKNOWN);
364:         checkSection(aclCacheSnapshot, action, exemplar, matchingPrincipals, host, matchingRuleBuilder);
365:         return matchingRuleBuilder.build();
366:     }
367: 
368:     static int matchesUpTo(
369:         String resource,
370:         String pattern
371:     ) {
372:         int i = 0;
373:         while (true) {
374:             if (resource.length() == i) break;
375:             if (pattern.length() == i) break;
376:             if (resource.charAt(i) != pattern.charAt(i)) break;
377:             i++;
378:         }
379:         return i;
380:     }
381: 
382:     private void checkSection(
383:             AclCache aclCacheSnapshot, Action action,
384:             StandardAcl exemplar,
385:             Set<KafkaPrincipal> matchingPrincipals,
386:             String host,
387:             MatchingRuleBuilder matchingRuleBuilder
388:     ) {
389:         String resourceName = action.resourcePattern().name();
390:         NavigableSet<StandardAcl> tailSet = aclCacheSnapshot.aclsByResource().tailSet(exemplar, true);
391:         Iterator<StandardAcl> iterator = tailSet.iterator();
392:         while (iterator.hasNext()) {
393:             StandardAcl acl = iterator.next();
394:             if (!acl.resourceType().equals(action.resourcePattern().resourceType())) {
395:                 // We've stepped outside the section for the resource type we care about and
396:                 // should stop scanning.
397:                 break;
398:             }
399:             int matchesUpTo = matchesUpTo(resourceName, acl.resourceName());
400:             if (matchesUpTo == acl.resourceName().length()) {
401:                 if (acl.patternType() == LITERAL && matchesUpTo != resourceName.length()) {
402:                     // This is a literal ACL whose name is a prefix of the resource name, but
403:                     // which doesn't match it exactly. We should skip over this ACL, but keep
404:                     // scanning in case there are any relevant PREFIX ACLs.
405:                     continue;
406:                 }
407: 
408:             } else if (!(acl.resourceName().equals(WILDCARD) && acl.patternType() == LITERAL)) {
409:                 // If the ACL resource name is NOT a prefix of the current resource name,
410:                 // and we're not dealing with the special case of a wildcard ACL, we've
411:                 // stepped outside of the section we care about. Scan for any other potential
412:                 // prefix matches.
413:                 exemplar = new StandardAcl(exemplar.resourceType(),
414:                     exemplar.resourceName().substring(0, matchesUpTo),
415:                     exemplar.patternType(),
416:                     exemplar.principal(),
417:                     exemplar.host(),
418:                     exemplar.operation(),
419:                     exemplar.permissionType());
420:                 tailSet = aclCacheSnapshot.aclsByResource().tailSet(exemplar, true);
421:                 iterator = tailSet.iterator();
422:                 continue;
423:             }
424:             matchingRuleBuilder.hasResourceAcls = true;
425:             AuthorizationResult result = findResult(action, matchingPrincipals, host, acl);
426:             if (ALLOWED == result) {
427:                 matchingRuleBuilder.allowAcl = acl;
428:             } else if (DENIED == result) {
429:                 matchingRuleBuilder.denyAcl = acl;
430:                 return;
431:             }
432:         }
433:     }
