435:     /**
436:      * The set of operations which imply DESCRIBE permission, when used in an ALLOW acl.
437:      */
438:     private static final Set<AclOperation> IMPLIES_DESCRIBE =
439:         Set.of(DESCRIBE, READ, WRITE, DELETE, ALTER);
440: 
441:     /**
442:      * The set of operations which imply DESCRIBE_CONFIGS permission, when used in an ALLOW acl.
443:      */
444:     private static final Set<AclOperation> IMPLIES_DESCRIBE_CONFIGS =
445:         Set.of(DESCRIBE_CONFIGS, ALTER_CONFIGS);
