458:     static KafkaPrincipal baseKafkaPrincipal(AuthorizableRequestContext context) {
459:         KafkaPrincipal sessionPrincipal = context.principal();
460:         return sessionPrincipal.getClass().equals(KafkaPrincipal.class)
461:             ? sessionPrincipal
462:             : new KafkaPrincipal(sessionPrincipal.getPrincipalType(), sessionPrincipal.getName());
463:     }
464: 
465:     static Set<KafkaPrincipal> matchingPrincipals(AuthorizableRequestContext context) {
466:         KafkaPrincipal sessionPrincipal = context.principal();
467:         KafkaPrincipal basePrincipal = sessionPrincipal.getClass().equals(KafkaPrincipal.class)
468:             ? sessionPrincipal
469:             : new KafkaPrincipal(sessionPrincipal.getPrincipalType(), sessionPrincipal.getName());
470:         return Set.of(basePrincipal, WILDCARD_KAFKA_PRINCIPAL);
471:     }
