473:     /**
474:      * Determine what the result of applying an ACL to the given action and request
475:      * context should be. Note that this function assumes that the resource name matches;
476:      * the resource name is not checked here.
477:      *
478:      * @param action             The input action.
479:      * @param matchingPrincipals The set of input matching principals
480:      * @param host               The input host.
481:      * @param acl                The input ACL.
482:      * @return                   null if the ACL does not match. The authorization result
483:      *                           otherwise.
484:      */
485:     static AuthorizationResult findResult(Action action,
486:                                           Set<KafkaPrincipal> matchingPrincipals,
487:                                           String host,
488:                                           StandardAcl acl) {
489:         // Check if the principal matches. If it doesn't, return no result (null).
490:         if (!matchingPrincipals.contains(acl.kafkaPrincipal())) {
491:             return null;
492:         }
493:         // Check if the host matches. If it doesn't, return no result (null).
494:         if (!acl.host().equals(WILDCARD) && !acl.host().equals(host)) {
495:             return null;
496:         }
497:         // Check if the operation field matches. Here we hit a slight complication.
498:         // ACLs for various operations (READ, WRITE, DELETE, ALTER), "imply" the presence
499:         // of DESCRIBE, even if it isn't explicitly stated. A similar rule applies to
500:         // DESCRIBE_CONFIGS.
501:         //
502:         // But this rule only applies to ALLOW ACLs. So for example, a DENY ACL for READ
503:         // on a resource does not DENY describe for that resource.
504:         if (acl.operation() != ALL) {
505:             if (acl.permissionType().equals(ALLOW)) {
506:                 switch (action.operation()) {
507:                     case DESCRIBE:
508:                         if (!IMPLIES_DESCRIBE.contains(acl.operation())) return null;
509:                         break;
510:                     case DESCRIBE_CONFIGS:
511:                         if (!IMPLIES_DESCRIBE_CONFIGS.contains(acl.operation())) return null;
512:                         break;
513:                     default:
514:                         if (action.operation() != acl.operation()) {
515:                             return null;
516:                         }
517:                         break;
518:                 }
519:             } else if (action.operation() != acl.operation()) {
520:                 return null;
521:             }
522:         }
523: 
524:         return acl.permissionType().equals(ALLOW) ? ALLOWED : DENIED;
525:     }
